/* $Id$ */
#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <stdlib.h>
#include <sys/stat.h>
#include <errno.h>
#include <string.h>


void
error(char *op, char* arg, char* file, int line) {
 fprintf(stderr,"%s. %s. %s (%s:%d)\n",
  op, arg, sys_errlist[errno], file, line);
}

void
mkDir(char *path, int level) {
 char newPath[4096];
/* printf("mkdir(%s)\n", path);*/
 if (mkdir(path, 0770) == -1) {
  error("mkdir", path, __FILE__, __LINE__);
  exit(2);
 }
 if (level > 1) {
  sprintf(newPath,"%s/d%d", path, level-1);
  mkDir(newPath, level-1);
 }
}

void
rmDir(char *path, int level) {
 char newPath[4096];
 if (level > 1) {
  sprintf(newPath,"%s/d%d", path, level-1);
  rmDir(newPath, level-1);
 }
/* printf("rmdir(%s):%d\n", path, level);*/
 if (rmdir(path) == -1) {
  error("unlink", path, __FILE__, __LINE__);
  exit(2);
 }
}

int
main(int argc, char **argv) {
 int fd, i, levels, pid;
 char path[128];

 if (argc != 2) {
  fprintf(stderr, "Usage: %s <levels>\n", argv[0]);
  exit(1);
 }

 levels = 10;
 sscanf(argv[1], "%d", &levels);
 if (levels > 210) levels = 210;
 pid = getpid();

 umask(0);
 sprintf(path,"p%05d.d%04d", pid, levels);
 mkDir(path, levels);
 rmDir(path, levels);
 return 0;
}
